// Build a structured dead-letter event from the error context.
// Never include execution input data (may contain sensitive content).
const err = $input.first().json;
const workflowName = err.workflow?.name || 'unknown';
const executionId = err.execution?.id || 'unknown';
const errorMsg = err.execution?.error?.message || 'Unknown error';
const timestamp = new Date().toISOString();

return [{
  json: {
    schema_version: 'v1',
    event: 'workflow_error',
    workflow_name: workflowName,
    execution_id: executionId,
    error_message: errorMsg,
    timestamp: timestamp,
    // Pulse task title stays generic — no sensitive data from the error payload
    task_title: `[n8n ERROR] ${workflowName} failed at ${timestamp.slice(0, 16).replace('T', ' ')} UTC`,
    task_priority: 'high',
    assigned_to: 'dave'
  }
}];
